#include <iostream>
#include <vector>
#include <algorithm>

class Solution {
public:
    bool solve(std::vector<int>& nums) {
        for (int i = 0; i < nums.size(); i++) {
            int min_idx = i;
            for (int j = i + 1; j < nums.size(); j++) {
                if (nums[j] < nums[i]) {
                    min_idx = j;
                }
            }
            if (min_idx != i) {
                std::swap(nums[i], nums[min_idx]);
            }
        }
        return true;
    }
};

int main() {
    std::vector<int> nums = {4, 3, 2, 1};
    Solution sol;
    sol.solve(nums);
    for (int num : nums) {
        std::cout << num << ' ';
    }
    return 0;

}
